document.addEventListener("DOMContentLoaded",function(){const e=document.getElementById("registrationForm"),t="localhost"===window.location.hostname?"http://localhost:3000":"https://rentify.azurewebsites.net";e&&e.addEventListener("submit",async function(n){n.preventDefault();const o=document.getElementById("login").value,a=document.getElementById("fullName").value,l={login:o,email:document.getElementById("email").value,name:a,role:document.getElementById("role").value,bio:document.getElementById("bio").value,password:document.getElementById("password").value},d=e.querySelector('button[type="submit"]');d.disabled=!0;try{const e=`${t}/auth/register`,n=await fetch(e,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(l)}),o=await n.json();n.ok?(alert("Success! Registration complete."),window.location.href="localhost"===window.location.hostname?"http://localhost:3000/api#/":"https://rentify.azurewebsites.net/api#"):alert("Backend error: "+(o.message||"Check your data"))}catch(e){alert("Connection failed. Is the backend running?")}finally{d.disabled=!1}})});